    /**
     * Finds the maximum integer in an array using iteration.
     *
     * @param numbers An array of integers.
     * @return The largest number in the array.
     */
    public static int findMax(int[] numbers) {
        if (numbers == null || numbers.length == 0) {
            throw new IllegalArgumentException("Array cannot be null or empty");
        }

        int max = numbers[0];
        for (int i = 1; i < numbers.length; i++) {
            if (numbers[i] > max) {
                max = numbers[i];
            }
        }
        return max;
    }

    public static void main(String[] args) {
        int[] nums = {34, -56, 98, 75};
        System.out.println(findMax(nums)); // Output: 98

        int[] negativeNums = {-23, -45, -67, -12};
        System.out.println(findMax(negativeNums)); // Output: -12

        int[] singleElement = {42};
        System.out.println(findMax(singleElement)); // Output: 42
    }
}
